d rgba(15,23,42,.06);overflow:hidden}.tcc-radar-line{position:absolute;top:58px;left:28px;right:28px;height:8px;background:linear-gradient(90deg,#dbeafe 0%,#bfdbfe 35%,#d1fae5 100%);border-radius:999px}.tcc-radar-marker{position:absolute;top:72px;font-size:10px;color:#64748b;font-weight:800;transform:translateX(-50%);white-space:nowrap}.tcc-radar-marker.start{left:28px;transform:none}.tcc-radar-marker.end{right:28px;left:auto;transform:none}.tcc-radar-avatar{position:absolute;top:58px;transform:translate(-50%,-50%);width:46px;height:46px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:900;color:#fff;font-size:12px;cursor:pointer;box-shadow:0 7px 18px rgba(15,23,42,.22);border:3px solid #fff;transition:transform .15s ease,box-shadow .15s ease;user-select:none}.tcc-radar-avatar:hover{transform:translate(-50%,-50%) scale(1.05);box-shadow:0 10px 24px rgba(15,23,42,.28)}.tcc-radar-avatar.selected{outline:3px solid rgba(18,53,95,.26);outline-offset:4px}.tcc-radar-avatar.green{background:#16a34a}.tcc-radar-avatar.orange{background:#f59e0b}.tcc-radar-avatar.red{background:#dc2626}.tcc-radar-avatar.blue{background:#2563eb}.tcc-radar-avatar.purple{background:#7c3aed}.tcc-radar-label{position:absolute;top:49px;left:50%;transform:translateX(-50%);font-size:11px;font-weight:800;color:#334155;white-space:nowrap;max-width:110px;overflow:hidden;text-overflow:ellipsis}.tcc-radar-score{position:absolute;top:-24px;left:50%;transform:translateX(-50%);font-size:10px;font-weight:900;color:#334155;background:#fff;border:1px solid rgba(15,23,42,.08);border-radius:999px;padding:3px 6px;white-space:nowrap}.tcc-radar-legend{display:flex;flex-wrap:wrap;gap:8px;margin-top:13px}.tcc-legend-pill{display:inline-flex;align-items:center;gap:6px;border-radius:999px;padding:6px 9px;background:#f8fafc;border:1px solid rgba(15,23,42,.06);font-size:11px;font-weight:800;color:#475569}.tcc-dot{width:9px;height:9px;border-radius:999px;display:inline-block}.tcc-dot.green{background:#16a34a}.tcc-dot.orange{background:#f59e0b}.tcc-dot.red{background:#dc2626}.tcc-dot.blue{background:#2563eb}.tcc-dot.purple{background:#7c3aed}.tcc-queue{display:flex;flex-direction:column;gap:12px}.tcc-item{display:flex;justify-content:space-between;align-items:center;gap:14px;padding:14px;border-radius:15px;background:#f8fbfd;border:1px solid rgba(15,23,42,.06)}.tcc-item-left{display:flex;gap:12px;align-items:center;min-width:0}.tcc-avatar{width:44px;height:44px;border-radius:50%;background:#12355f;color:#fff;display:flex;align-items:center;justify-content:center;font-weight:900;flex:0 0 auto}.tcc-meta{display:flex;flex-direction:column;min-width:0}.tcc-name{font-weight:800;color:#152235;line-height:1.25}.tcc-sub{font-size:12px;color:#64748b;line-height:1.35;overflow:hidden;text-overflow:ellipsis}.tcc-severity{display:inline-flex;align-items:center;justify-content:center;border-radius:999px;padding:4px 8px;font-size:10px;font-weight:900;text-transform:uppercase;letter-spacing:.06em;margin-top:6px;align-self:flex-start}.tcc-severity.high{background:#fee2e2;color:#991b1b;border:1px solid #fca5a5}.tcc-severity.medium{background:#fef3c7;color:#92400e;border:1px solid #fde68a}.tcc-severity.low{background:#e0f2fe;color:#075985;border:1px solid #bae6fd}.tcc-actions{display:flex;gap:8px;flex:0 0 auto}.tcc-btn{display:inline-flex;align-items:center;justify-content:center;min-height:34px;padding:0 11px;border-radius:10px;font-size:12px;font-weight:800;border:1px solid rgba(15,23,42,.08);cursor:pointer;text-decoration:none}.tcc-btn.primary{background:#12355f;color:#fff;border-color:#12355f}.tcc-btn.warn{background:#fff7ed;color:#92400e;border-color:#fed7aa}.tcc-btn.secondary{background:#f1f5f9;color:#334155}.tcc-empty{padding:16px;border-radius:14px;border:1px dashed rgba(15,23,42,.15);background:#fbfdff;color:#64748b;font-size:14px}.tcc-error{padding:14px;border-radius:14px;border:1px solid #fecaca;background:#fef2f2;color:#991b1b;font-weight:800;font-size:13px}.tcc-loading{color:#64748b;font-size:14px;padding:12px 0}.tcc-student-panel{position:sticky;top:14px}.tcc-student-empty{padding:18px;border-radius:16px;background:#f8fbfd;border:1px dashed rgba(15,23,42,.16);color:#64748b;font-size:14px;line-height:1.45}.tcc-student-head{display:flex;align-items:center;gap:13px;margin-bottom:15px}.tcc-student-avatar{width:58px;height:58px;border-radius:999px;display:flex;align-items:center;justify-content:center;background:#12355f;color:#fff;font-size:16px;font-weight:900;box-shadow:0 8px 20px rgba(18,53,95,.22);flex:0 0 auto}.tcc-student-name{font-size:21px;line-height:1.05;color:#152235;font-weight:900;letter-spacing:-.025em}.tcc-student-email{margin-top:4px;font-size:12px;color:#64748b;overflow:hidden;text-overflow:ellipsis}.tcc-student-state-row{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:14px}.tcc-status-pill{display:inline-flex;align-items:center;justify-content:center;border-radius:999px;padding:6px 9px;font-size:11px;font-weight:900;border:1px solid rgba(15,23,42,.08);background:#f1f5f9;color:#334155}.tcc-status-pill.strong{background:#dcfce7;color:#166534;border-color:#86efac}.tcc-status-pill.stable{background:#dbeafe;color:#1d4ed8;border-color:#93c5fd}.tcc-status-pill.drifting{background:#fef3c7;color:#92400e;border-color:#fde68a}.tcc-status-pill.needs_contact{background:#fee2e2;color:#991b1b;border-color:#fca5a5}.tcc-snapshot-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin-bottom:14px}.tcc-snapshot-tile{border-radius:15px;border:1px solid rgba(15,23,42,.06);background:#fbfdff;padding:12px;min-width:0}.tcc-snapshot-label{font-size:10px;text-transform:uppercase;letter-spacing:.12em;color:#64748b;font-weight:900}.tcc-snapshot-value{margin-top:7px;font-size:24px;line-height:1;color:#152235;font-weight:900}.tcc-snapshot-sub{margin-top:6px;font-size:12px;color:#64748b;line-height:1.35}.tcc-mini-bar{height:8px;width:100%;border-radius:999px;background:#e7edf4;overflow:hidden;margin-top:9px}.tcc-mini-bar>span{display:block;height:8px;border-radius:999px;background:linear-gradient(90deg,#102845 0%,#214d91 100%)}.tcc-issues-list{display:flex;flex-direction:column;gap:8px;max-height:320px;overflow:auto;padding-right:2px}.tcc-issue-row{border-radius:13px;border:1px solid rgba(15,23,42,.06);background:#f8fbfd;padding:10px 11px}.tcc-issue-title{font-size:13px;color:#152235;font-weight:800;line-height:1.25}.tcc-issue-meta{margin-top:4px;font-size:11px;color:#64748b;line-height:1.35}.tcc-panel-actions{display:flex;flex-wrap:wrap;gap:8px;margin-top:14px}
