<div class="tcc-shell">
    <div class="tcc-header">
        <div class="tcc-title-wrap">
            <div class="tcc-title">Instructor Theory Control Center</div>
            <div class="tcc-subtitle">Live action queue, cohort radar, and training-risk visibility.</div>
        </div>
        <select id="cohortSelect" class="tcc-select" aria-label="Select cohort"></select>
    </div>

    <div class="tcc-grid">
        <div class="tcc-main-col">
            <div class="tcc-card"><div class="tcc-section-head"><div><div class="tcc-section-title">Cohort Health</div><div class="tcc-section-sub">At-a-glance status for the selected cohort.</div></div></div><div id="healthStrip" class="tcc-health-strip"><div class="tcc-loading">Loading cohort health…</div></div></div>
            <div class="tcc-card"><div class="tcc-section-head"><div><div class="tcc-section-title">Cohort Radar</div><div class="tcc-section-sub">Students positioned by completed progress across the cohort lesson track.</div></div><div id="radarCount" class="tcc-count-pill">—</div></div><div id="radarTrack" class="tcc-radar-track"><div class="tcc-radar-line"></div><div class="tcc-radar-marker start">Start</div><div class="tcc-radar-marker end">Complete</div><div id="radarAvatars"></div></div><div class="tcc-radar-legend"><span class="tcc-legend-pill"><span class="tcc-dot green"></span> On track</span><span class="tcc-legend-pill"><span class="tcc-dot orange"></span> At risk</span><span class="tcc-legend-pill"><span class="tcc-dot red"></span> Blocked</span><span class="tcc-legend-pill"><span class="tcc-dot blue"></span> Action pending</span><span class="tcc-legend-pill"><span class="tcc-dot purple"></span> System issue</span></div></div>
            <div class="tcc-card"><div class="tcc-section-head"><div><div class="tcc-section-title">Needs My Action</div><div class="tcc-section-sub">Instructor-facing items that need review, approval, or safe follow-up.</div></div><div id="queueCount" class="tcc-count-pill">—</div></div><div id="actionQueue" class="tcc-queue"><div class="tcc-loading">Loading action queue…</div></div></div>
        </div>
        <div class="tcc-side-col"><div class="tcc-card tcc-student-panel"><div class="tcc-section-head"><div><div class="tcc-section-title">Student Deep Dive</div><div class="tcc-section-sub">Tap a Radar avatar or queue item to inspect the student.</div></div></div><div id="studentPanel" class="tcc-student-empty">Select a student to view progress, motivation signal, cohort comparisons, and current blockers.</div></div></div>
    </div>
</div>

<script>
(function(){var cohortId=0;var selectedStudentId=0;function escapeHtml(value){return String(value===null||value===undefined?'':value).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;')}function api(action,params){params=params||{};params.action=action;return fetch('/instructor/api/theory_control_center_api.php?'+new URLSearchParams(params),{credentials:'same-origin',cache:'no-store'}).then(function(response){return response.json()})}function showError(containerId,message){var container=document.getElementById(containerId);if(container)container.innerHTML='<div class="tcc-error">'+escapeHtml(message)+'</div>'}function renderStudentEmpty(){var panel=document.getElementById('studentPanel');if(panel){panel.className='tcc-student-empty';panel.innerHTML='Select a student to view progress, motivation signal, cohort comparisons, and current blockers.'}}function loadCohorts(){api('cohort_overview').then(function(data){var select=document.getElementById('cohortSelect');select.innerHTML='';if(!data.ok||!data.cohorts||!data.cohorts.length){select.innerHTML='<option value="">No cohorts found</option>';showError('actionQueue','No cohorts were returned by the API.');return}data.cohorts.forEach(function(c){var opt=document.createElement('option');opt.value=c.id;opt.textContent=c.name;select.appendChild(opt)});cohortId=parseInt(data.cohorts[0].id,10)||0;select.value=cohortId;loadAll()}).catch(function(){showError('actionQueue','Unable to load cohorts.')})}function loadAll(){if(!cohortId)return;selectedStudentId=0;renderStudentEmpty();loadOverview();loadQueue()}function loadOverview(){document.getElementById('healthStrip').innerHTML='<div class="tcc-loading">Loading cohort health…</div>';document.getElementById('radarAvatars').innerHTML='';document.getElementById('radarCount').textContent='—';api('cohort_overview',{cohort_id:cohortId}).then(function(data){if(!data.ok){showError('healthStrip',data.message||data.error||'Unable to load cohort overview.');return}renderHealth(data);renderRadar(data)}).catch(function(){showError('healthStrip','Unable to load cohort overview.')})}function renderHealth(data){var s=data.summary||{};document.getElementById('healthStrip').innerHTML='<div class="tcc-health-card"><div class="tcc-health-label">Students</div><div class="tcc-health-value">'+escapeHtml(s.student_count||0)+'</div><div class="tcc-health-note">Active in this cohort</div></div><div class="tcc-health-card"><div class="tcc-health-label">On Track</div><div class="tcc-health-value">'+escapeHtml(s.on_track_count||0)+'</div><div class="tcc-health-note">No immediate action</div></div><div class="tcc-health-card"><div class="tcc-health-label">At Risk</div><div class="tcc-health-value">'+escapeHtml(s.at_risk_count||0)+'</div><div class="tcc-health-note">Needs monitoring</div></div><div class="tcc-health-card"><div class="tcc-health-label">Blocked</div><div class="tcc-health-value">'+escapeHtml(s.blocked_count||0)+'</div><div class="tcc-health-note">Action required</div></div>'}function radarColor(student){if(student.state==='blocked')return'red';if(student.pending_action_count&&parseInt(student.pending_action_count,10)>0)return'blue';if(student.state==='at_risk')return'orange';return'green'}function renderRadar(data){var container=document.getElementById('radarAvatars');var count=document.getElementById('radarCount');var students=data.students||[];container.innerHTML='';count.textContent=students.length+' student'+(students.length===1?'':'s');if(!students.length){container.innerHTML='<div class="tcc-empty">No students found for this cohort.</div>';return}students.forEach(function(s,idx){var progress=parseInt(s.progress_pct,10);if(isNaN(progress))progress=0;if(progress<0)progress=0;if(progress>100)progress=100;var verticalNudge=(idx%3)*5;var el=document.createElement('div');el.className='tcc-radar-avatar '+radarColor(s);el.style.left=progress+'%';el.style.top=(58+verticalNudge)+'px';el.title=s.name+' · '+progress+'% · '+s.state;el.setAttribute('role','button');el.setAttribute('tabindex','0');el.setAttribute('aria-label',s.name+' progress '+progress+' percent');el.setAttribute('data-student-id',s.student_id||0);el.innerHTML='<span class="tcc-radar-score">'+progress+'%</span>'+escapeHtml(s.avatar_initials||'S')+'<span class="tcc-radar-label">'+escapeHtml((s.name||'Student').split(' ')[0])+'</span>';el.onclick=function(){loadStudentPanel(s.student_id)};el.onkeydown=function(ev){if(ev.key==='Enter'||ev.key===' '){ev.preventDefault();el.click()}};container.appendChild(el)})}function trendText(value,average,lowerIsBetter){if(value===null||value===undefined||average===null||average===undefined)return'—';var v=parseFloat(value),a=parseFloat(average);if(isNaN(v)||isNaN(a))return'—';if(Math.abs(v-a)<.1)return'≈ cohort';var better=lowerIsBetter?(v<a):(v>a);return better?'better than cohort':'worse than cohort'}function loadStudentPanel(studentId){selectedStudentId=parseInt(studentId,10)||0;var panel=document.getElementById('studentPanel');if(!selectedStudentId||!panel)return;Array.prototype.forEach.call(document.querySelectorAll('.tcc-radar-avatar'),function(el){el.classList.remove('selected');if(parseInt(el.getAttribute('data-student-id')||'0',10)===selectedStudentId)el.classList.add('selected')});panel.className='';panel.innerHTML='<div class="tcc-loading">Loading student snapshot…</div>';api('student_snapshot',{cohort_id:cohortId,student_id:selectedStudentId}).then(function(data){if(!data.ok){panel.innerHTML='<div class="tcc-error">'+escapeHtml(data.message||data.error||'Unable to load student snapshot.')+'</div>';return}renderStudentPanel(data)}).catch(function(){panel.innerHTML='<div class="tcc-error">Unable to load student snapshot.</div>'})}function renderStudentPanel(data){var panel=document.getElementById('studentPanel');var st=data.student||{};var p=data.progress||{};var c=data.comparison||{};var m=data.motivation||{};var issues=data.main_issues||[];var progressPct=parseInt(p.progress_pct||0,10);if(isNaN(progressPct))progressPct=0;if(progressPct<0)progressPct=0;if(progressPct>100)progressPct=100;var issueHtml='';if(!issues.length){issueHtml='<div class="tcc-empty">No current blockers or system issues returned for this student.</div>'}else{issues.slice(0,8).forEach(function(issue){issueHtml+='<div class="tcc-issue-row"><div class="tcc-issue-title">'+escapeHtml(issue.title||issue.type||'Issue')+'</div><div class="tcc-issue-meta">Lesson '+escapeHtml(issue.lesson_id||'—')+' · '+escapeHtml(issue.lesson_title||'')+' · '+escapeHtml(issue.status||'')+'</div></div>'});if(issues.length>8){issueHtml+='<div class="tcc-issue-row"><div class="tcc-issue-title">+'+(issues.length-8)+' more issue(s)</div><div class="tcc-issue-meta">Full lesson/intervention timeline will handle the expanded view in the next phase.</div></div>'}}panel.className='';panel.innerHTML='<div class="tcc-student-head"><div class="tcc-student-avatar">'+escapeHtml(st.avatar_initials||'S')+'</div><div style="min-width:0;"><div class="tcc-student-name">'+escapeHtml(st.name||'Student')+'</div><div class="tcc-student-email">'+escapeHtml(st.email||'')+'</div></div></div><div class="tcc-student-state-row"><span class="tcc-status-pill '+escapeHtml(m.level||'')+'">'+escapeHtml(m.label||'Motivation signal')+'</span><span class="tcc-status-pill">Trend: '+escapeHtml(m.trend||'—')+'</span><span class="tcc-status-pill">Issues: '+escapeHtml(issues.length)+'</span></div><div class="tcc-snapshot-grid"><div class="tcc-snapshot-tile"><div class="tcc-snapshot-label">Progress</div><div class="tcc-snapshot-value">'+progressPct+'%</div><div class="tcc-mini-bar"><span style="width:'+progressPct+'%;"></span></div><div class="tcc-snapshot-sub">'+escapeHtml(p.passed_lessons||0)+'/'+escapeHtml(p.total_lessons||0)+' lessons passed</div></div><div class="tcc-snapshot-tile"><div class="tcc-snapshot-label">Avg Score</div><div class="tcc-snapshot-value">'+(c.avg_score!==null&&c.avg_score!==undefined?escapeHtml(c.avg_score)+'%':'—')+'</div><div class="tcc-snapshot-sub">Cohort avg: '+(c.cohort_avg_score!==null&&c.cohort_avg_score!==undefined?escapeHtml(c.cohort_avg_score)+'%':'—')+'<br>'+escapeHtml(trendText(c.avg_score,c.cohort_avg_score,false))+'</div></div><div class="tcc-snapshot-tile"><div class="tcc-snapshot-label">Deadlines Missed</div><div class="tcc-snapshot-value">'+escapeHtml(c.deadlines_missed||0)+'</div><div class="tcc-snapshot-sub">Cohort avg: '+escapeHtml(c.cohort_avg_deadlines_missed||0)+'<br>'+escapeHtml(trendText(c.deadlines_missed,c.cohort_avg_deadlines_missed,true))+'</div></div><div class="tcc-snapshot-tile"><div class="tcc-snapshot-label">Failed Attempts</div><div class="tcc-snapshot-value">'+escapeHtml(c.failed_attempts||0)+'</div><div class="tcc-snapshot-sub">Cohort avg: '+escapeHtml(c.cohort_avg_failed_attempts||0)+'<br>'+escapeHtml(trendText(c.failed_attempts,c.cohort_avg_failed_attempts,true))+'</div></div></div><div class="tcc-section-title" style="font-size:16px;margin:4px 0 10px;">Current Blockers / Issues</div><div class="tcc-issues-list">'+issueHtml+'</div><div class="tcc-panel-actions"><button class="tcc-btn primary" type="button">Lessons</button><button class="tcc-btn secondary" type="button">Interventions</button><button class="tcc-btn warn" type="button">System Watch</button></div>'}function loadQueue(){document.getElementById('actionQueue').innerHTML='<div class="tcc-loading">Loading action queue…</div>';document.getElementById('queueCount').textContent='—';api('action_queue',{cohort_id:cohortId}).then(function(data){var container=document.getElementById('actionQueue');var count=document.getElementById('queueCount');if(!data.ok){showError('actionQueue',data.message||data.error||'Unable to load action queue.');return}var items=data.items||[];count.textContent=items.length+' item'+(items.length===1?'':'s');container.innerHTML='';if(!items.length){container.innerHTML='<div class="tcc-empty">No instructor actions required for this cohort right now.</div>';return}items.forEach(function(item){var reviewHref='';if(item.token){if(item.action_type==='instructor_approval')reviewHref='/instructor/instructor_approval.php?token='+encodeURIComponent(item.token);else reviewHref='/student/remediation_action.php?token='+encodeURIComponent(item.token)}var severity=item.severity||'low';var el=document.createElement('div');el.className='tcc-item';el.innerHTML='<div class="tcc-item-left"><div class="tcc-avatar">'+escapeHtml(item.avatar_initials||'S')+'</div><div class="tcc-meta"><div class="tcc-name">'+escapeHtml(item.student_name||'Student')+'</div><div class="tcc-sub">'+escapeHtml(item.lesson_title||'No lesson title')+'</div><div class="tcc-sub">'+escapeHtml(item.reason||item.action_type||'Required action')+'</div><span class="tcc-severity '+escapeHtml(severity)+'">'+escapeHtml(severity)+'</span></div></div><div class="tcc-actions">'+(reviewHref?'<a class="tcc-btn primary" href="'+escapeHtml(reviewHref)+'">Review</a>':'<button class="tcc-btn primary" type="button">Review</button>')+'<button class="tcc-btn warn" type="button" data-action-id="'+escapeHtml(item.required_action_id||'')+'">Safe Fix</button></div>';var left=el.querySelector('.tcc-item-left');if(left){left.style.cursor='pointer';left.onclick=function(){loadStudentPanel(item.student_id)}}container.appendChild(el)})}).catch(function(){showError('actionQueue','Unable to load action queue.')})}document.getElementById('cohortSelect').addEventListener('change',function(){cohortId=parseInt(this.value,10)||0;loadAll()});loadCohorts()})();
